import { useState, useEffect } from 'react'
import NumberFormat from 'react-number-format'
import { useLocation, useHistory } from 'react-router-dom'

import Header from '../components/Header'
import SignaturePad from '../components/SignaturePad'

function Employee() {
  const { state } = useLocation()

  const history = useHistory()

  const [ data, setData ] = useState({ ...state })

  useEffect(() => {
    // Carregar dados salvos do localStorage
    const savedData = localStorage.getItem('employeeData')
    if (savedData) {
      const parsedData = JSON.parse(savedData)
      setData(prevData => ({ ...prevData, ...parsedData }))
    }
  }, [])

  function handleChange(e) {
    setData({ ...data, [ e.target.name ]: e.target.value })
  }

  function handleSubmit() {
    // Salvar dados no localStorage
    localStorage.setItem('employeeData', JSON.stringify(data))

    // Salvar no array de funcionários
    const savedEmployees = localStorage.getItem('employees')
    let employees = savedEmployees ? JSON.parse(savedEmployees) : []

    // Verificar se já existe (edição) ou é novo
    const existingIndex = employees.findIndex(emp => emp.cpf === data.cpf)
    if (existingIndex >= 0) {
      employees[existingIndex] = data
    } else {
      employees.push(data)
    }

    localStorage.setItem('employees', JSON.stringify(employees))

    history.push('/document', data)
  }

  return (
    <div className="employee container">
      <form onSubmit={handleSubmit}>
        <Header pathname="/" state={data}>
          Recibo de Serviços Prestados
        </Header>

        <fieldset>
          <label>
            <span>Nome do Funcionário</span>
            <input
              type="text" name="employee"
              required autoFocus={true}
              value={data.employee || ''} onChange={handleChange}
            />
          </label>
          <label>
            <span>CPF</span>
            <NumberFormat
              format="###.###.###-##" allowEmptyFormatting mask="_" required 
              name="cpf" value={data.cpf || ''} onChange={handleChange}
            />
          </label>
          <label>
            <span>RG</span>
            <NumberFormat
              format="##.###.###-##" allowEmptyFormatting mask="_" required 
              name="rg" value={data.rg || ''} onChange={handleChange}
            />
          </label>   
        </fieldset>

        <SignaturePad onSignatureChange={(sig) => setData({ ...data, signature: sig })} />

        <div style={{ marginTop: '20px', textAlign: 'center' }}>
          <button type="button" onClick={() => {
            localStorage.removeItem('employeeData')
            setData({ ...state })
            window.alert('Dados salvos foram limpos!')
          }} style={{
            backgroundColor: '#dc3545',
            color: 'white',
            border: 'none',
            padding: '10px 20px',
            borderRadius: '4px',
            cursor: 'pointer',
            fontSize: '14px'
          }}>
            Limpar Dados Salvos
          </button>
        </div>

        <button>Avançar</button>
      </form>
    </div>
  )
}

export default Employee
