function docFooter(employee, signature) {
  const signatureRow = signature
    ? [
        {
          image: signature,
          width: 150,
          alignment: 'center',
          margin: [0, 20, 0, 0]
        }
      ]
    : [
        {
          text: '__________________________________________________',
          style: 'footer',
          margin: [0, 30, 0, 0],
          border: [true, false, true, false]
        }
      ]

  const docFooter = [
    {
      table: {
        widths: ['*'],
        body: [
          signatureRow,
          [
            {
              text: employee,
              style: 'footer',
              margin: [0, 0, 0, 20],
              border: [true, false, true, true]
            }
          ]
        ]
      }
    }
  ]

  return docFooter
}

export default docFooter
