import { useState } from "react"
import { useHistory, useLocation } from 'react-router-dom'

import Header from '../components/Header'

function Document() {
  const history = useHistory()

  const { state } = useLocation()

  function handleSubmit(e) {
    e.preventDefault()
    history.push('/servico-prestado', state)
  }

  return (
    <div className="document container" onSubmit={handleSubmit}>
      <form>
        <Header pathname="/employee" state={state}>Recibo de Serviços Prestados</Header>
        
        <fieldset>
          <p style={{ textAlign: 'center', margin: '20px 0', fontSize: '18px', fontWeight: 'bold' }}>
            Recibo de Serviço Prestado
          </p>
        </fieldset>

        <button>Avançar</button>
      </form>
    </div>
  )
}

export default Document
