import { useState, useEffect } from 'react'
import { useHistory } from 'react-router-dom'

import Header from '../components/Header'

function Dashboard() {
  const history = useHistory()
  const [employees, setEmployees] = useState([])
  const [services, setServices] = useState([])
  const [activeTab, setActiveTab] = useState('employees')

  useEffect(() => {
    loadData()
  }, [])

  function loadData() {
    // Carregar funcionários
    const savedEmployees = localStorage.getItem('employees')
    if (savedEmployees) {
      setEmployees(JSON.parse(savedEmployees))
    }

    // Carregar serviços
    const savedServices = localStorage.getItem('services')
    if (savedServices) {
      setServices(JSON.parse(savedServices))
    }
  }

  function deleteEmployee(index) {
    if (window.confirm('Tem certeza que deseja excluir este funcionário?')) {
      const updatedEmployees = employees.filter((_, i) => i !== index)
      setEmployees(updatedEmployees)
      localStorage.setItem('employees', JSON.stringify(updatedEmployees))
    }
  }

  function deleteService(index) {
    if (window.confirm('Tem certeza que deseja excluir este serviço?')) {
      const updatedServices = services.filter((_, i) => i !== index)
      setServices(updatedServices)
      localStorage.setItem('services', JSON.stringify(updatedServices))
    }
  }

  function editEmployee(index) {
    const employee = employees[index]
    localStorage.setItem('employeeData', JSON.stringify(employee))
    history.push('/employee')
  }

  function editService(index) {
    const service = services[index]
    localStorage.setItem('editService', JSON.stringify(service))
    history.push('/servico-prestado')
  }

  function generateServiceReceipt(index) {
    const service = services[index]
    localStorage.setItem('editService', JSON.stringify(service))
    history.push('/servico-prestado')
  }

  return (
    <div className="dashboard container">
      <Header pathname="/" state={{}}>Dashboard - Gerenciamento</Header>

      <div className="tabs">
        <button
          className={activeTab === 'employees' ? 'active' : ''}
          onClick={() => setActiveTab('employees')}
        >
          Funcionários ({employees.length})
        </button>
        <button
          className={activeTab === 'services' ? 'active' : ''}
          onClick={() => setActiveTab('services')}
        >
          Serviços ({services.length})
        </button>
      </div>

      {activeTab === 'employees' && (
        <div className="employees-section">
          <div className="section-header">
            <h2>Funcionários</h2>
            <button
              onClick={() => {
                localStorage.removeItem('employeeData')
                history.push('/employee')
              }}
              className="add-button"
            >
              + Novo Funcionário
            </button>
          </div>

          {employees.length === 0 ? (
            <p className="empty-message">Nenhum funcionário cadastrado ainda.</p>
          ) : (
            <div className="employees-list">
              {employees.map((employee, index) => (
                <div key={index} className="employee-card">
                  <div className="employee-info">
                    <h3>{employee.employee}</h3>
                    <p>CPF: {employee.cpf}</p>
                    <p>RG: {employee.rg}</p>
                  </div>
                  <div className="employee-actions">
                    <button onClick={() => editEmployee(index)} className="edit-btn">
                      Editar
                    </button>
                    <button onClick={() => deleteEmployee(index)} className="delete-btn">
                      Excluir
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {activeTab === 'services' && (
        <div className="services-section">
          <div className="section-header">
            <h2>Serviços Prestados</h2>
            <button
              onClick={() => {
                localStorage.removeItem('serviceData')
                history.push('/servico-prestado')
              }}
              className="add-button"
            >
              + Novo Serviço
            </button>
          </div>

          {services.length === 0 ? (
            <p className="empty-message">Nenhum serviço cadastrado ainda.</p>
          ) : (
            <div className="services-list">
              {services.map((service, index) => (
                <div key={index} className="service-card">
                  <div className="service-info">
                    <h3>{service.employee}</h3>
                    <p>Data: {service.date}</p>
                    <p>Valor: R$ {service.value}</p>
                    <p>Serviço: {service.serviceDescription?.substring(0, 50)}...</p>
                  </div>
                  <div className="service-actions">
                    <button onClick={() => generateServiceReceipt(index)} className="edit-btn">
                      Reutilizar serviço / Gerar novo recibo
                    </button>
                    <button onClick={() => editService(index)} className="edit-btn">
                      Editar
                    </button>
                    <button onClick={() => deleteService(index)} className="delete-btn">
                      Excluir
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default Dashboard