import { useState, useEffect } from 'react'
import { useLocation } from 'react-router-dom'
import pdfMake from 'pdfmake/build/pdfmake'
import pdfFonts from 'pdfmake/build/vfs_fonts'

import Header from  '../../components/Header'
import Loader from '../../components/Loader'
import Lock from '../../components/Lock'

import servicoPrestado from '../../documents/servico-prestado'

import FormatDate from '../../helpers/format-date'

function ServicoPrestado() {
  pdfMake.vfs = pdfFonts.pdfMake.vfs

  const formatDate = new FormatDate()

  const { state } = useLocation()

  const [ date, setDate ] = useState(formatDate.today())
  const [ serviceDescription, setServiceDescription ] = useState('')
  const [ value, setValue ] = useState('')
  const [ loader, setLoader ] = useState(false)
  const [ lock, setLock ] = useState(false)

  useEffect(() => {
    // Carregar dados salvos do localStorage
    const savedData = localStorage.getItem('serviceData')
    if (savedData) {
      const parsedData = JSON.parse(savedData)
      setServiceDescription(parsedData.serviceDescription || '')
      setValue(parsedData.value || '')
    }

    // Verificar se é edição de serviço existente
    const editServiceData = localStorage.getItem('editService')
    if (editServiceData) {
      const service = JSON.parse(editServiceData)
      setServiceDescription(service.serviceDescription || '')
      setValue(service.value || '')
      setDate(service.date || formatDate.today())
      localStorage.removeItem('editService') // Limpar após carregar
    }
  }, [])

  function generate(event) {
    event.preventDefault()

    const data = {
      ...state,
      date,
      serviceDescription,
      value: parseFloat(value) || 0
    }

    // Salvar dados no localStorage
    localStorage.setItem('serviceData', JSON.stringify({
      serviceDescription,
      value
    }))

    // Salvar no array de serviços
    const savedServices = localStorage.getItem('services')
    let services = savedServices ? JSON.parse(savedServices) : []

    // Verificar se é edição (tem ID) ou novo serviço
    const editServiceData = localStorage.getItem('editService')
    let serviceId = null
    if (editServiceData) {
      const editService = JSON.parse(editServiceData)
      serviceId = editService.id
    }

    if (serviceId) {
      // Edição: encontrar e atualizar
      const existingIndex = services.findIndex(svc => svc.id === serviceId)
      if (existingIndex >= 0) {
        services[existingIndex] = { ...data, id: serviceId }
      }
    } else {
      // Novo: adicionar com ID único
      data.id = Date.now()
      services.push(data)
    }

    localStorage.setItem('services', JSON.stringify(services))

    pdfMake.createPdf(servicoPrestado(data)).open()
  }

  function handleClick(e) {
    lock ? setLock(false) : setLock(true)
  }

  return (
    <div className="servico-prestado container">
      <form onSubmit={generate}>
        <Header pathname="/dashboard" state={state}>
          Serviço Prestado
        </Header>
        <fieldset>
          <label>
            <span>Data</span>
            <input
              type="date" value={date} required
              onChange={event => setDate(event.target.value)}
            />
          </label>
          <label>
            <span>Descrição do Serviço</span>
            <textarea
              value={serviceDescription}
              onChange={event => setServiceDescription(event.target.value)}
              placeholder="Descreva o serviço prestado..."
              rows="4"
              required
            />
          </label>
          <label>
            <span>Valor</span>
            <Lock lock={lock} handleClick={handleClick}>
              <input
                type="number"
                step="0.01"
                value={value}
                placeholder="0.00"
                onChange={event => setValue(event.target.value)}
                required
              />
            </Lock>
          </label>
        </fieldset>

        <div style={{ marginTop: '20px', textAlign: 'center' }}>
          <button type="button" onClick={() => {
            localStorage.removeItem('serviceData')
            setServiceDescription('')
            setValue('')
            window.alert('Dados de serviço salvos foram limpos!')
          }} style={{
            backgroundColor: '#dc3545',
            color: 'white',
            border: 'none',
            padding: '10px 20px',
            borderRadius: '4px',
            cursor: 'pointer',
            fontSize: '14px'
          }}>
            Limpar Dados Salvos
          </button>
        </div>

        <div style={{ display: 'flex', gap: '10px', justifyContent: 'center', marginBottom: '20px' }}>
          <button type="button" onClick={() => window.location.href = '/dashboard'} style={{
            backgroundColor: '#007bff',
            color: 'white',
            border: 'none',
            padding: '10px 20px',
            borderRadius: '4px',
            cursor: 'pointer',
            fontSize: '14px'
          }}>
            Voltar ao Dashboard
          </button>
        </div>

        <button>Gerar Recibo</button>
      </form>

      {loader && <Loader />}
    </div>
  )
}

export default ServicoPrestado