import { BrowserRouter, Switch, Route } from 'react-router-dom'

import Company from './pages/Company'
import Employee from './pages/Employee'
import Document from './pages/Document'
import ServicoPrestado from './pages/Document-Pages/Servico-Prestado'
import Dashboard from './pages/Dashboard'

import './css/style.css'
import './css/responsive.css'
import './components/SignaturePad/style.css'
import './pages/Dashboard.css'

function App() {
  return (
    <BrowserRouter>
      <Switch>
        <Route component={Company} path="/" exact />
        <Route component={Employee} path="/employee" />
        <Route component={Document} path="/document" />
        <Route component={ServicoPrestado} path="/servico-prestado" />
        <Route component={Dashboard} path="/dashboard" />
      </Switch>
    </BrowserRouter>
  )
}

export default App
