import docHeader from './partials/doc-header'
import docFooter from './partials/doc-footer'
import docStyles from './partials/doc-styles'

import Format from '../helpers/format'
import FormatDate from '../helpers/format-date'

function servicoPrestado(data) {
  const { value, date, serviceDescription, employee } = data
  const document = 'Recibo de Serviço Prestado'

  const format = new Format()
  const formatDate = new FormatDate()

  const docDefinition = {
    content: [
      ...docHeader({ ...data, document }),
      {
        table: {
          widths: ['*', '*'],
          body: [
            [
              {
                text: [
                  {
                    text: 'Valor: ',
                    style: 'label'
                  },
                  format.currency(value)
                ],
                border: [true, false, true, true]
              },
              {
                text: [
                  {
                    text: 'Data: ',
                    style: 'label'
                  },
                  formatDate.finalDate(date)
                ],
                border: [true, false, true, true]
              }
            ]
          ]
        }
      },
      {
        table: {
          widths: ['*'],
          body: [
            [
              {
                text: [
                  {
                    text: 'Serviço Prestado: ',
                    style: 'label'
                  },
                  serviceDescription
                ],
                margin: [10, 10, 10, 10],
                border: [true, false, true, false]
              }
            ],
            [
              {
                text: `Declaro que recebi a quantia líquida de ${format.currency(value)} - ${format.extensive(value)}, referente ao pagamento pelos serviços prestados.`,
                margin: [10, 10, 10, 2],
                border: [true, false, true, false]
              }
            ],
            [
              {
                text: 'Para clareza e documento, firmo o presente recibo, dando plena e geral quitação.',
                margin: [10, 0, 10, 10],
                border: [true, false, true, false]
              }
            ]
          ]
        }
      },
      ...docFooter(employee, data.signature)
    ],
    ...docStyles
  }

  return docDefinition
}

export default servicoPrestado